[asy]

draw((-10,-8)--(0,0)--(10,-8));
label("$A$",(0,0),N);

draw((-12,-18)--(-10,-12)--(-10,-18));
draw((-10,-12)--(-8,-18));

label("$A$",(-10,-10));
label("$A$",(-12,-18),S);
label("$B$",(-10,-18),S);
label("$C$",(-8,-18),S);

draw((0,0)--(0,-8));

draw((-2,-18)--(0,-12)--(0,-18));
draw((0,-12)--(2,-18));

label("$B$",(0,-10));
label("$A$",(-2,-18),S);
label("$B$",(0,-18),S);
label("$C$",(2,-18),S);

draw((8,-18)--(10,-12)--(10,-18));
draw((10,-12)--(12,-18));

label("$C$",(10,-10));
label("$A$",(8,-18),S);
label("$B$",(10,-18),S);
label("$C$",(12,-18),S);

[/asy]

